const input = $input.first().json;

const raw =
  input.text ||
  input.output ||
  input.response ||
  input.message ||
  input.content ||
  input.data?.message ||
  input.data?.content ||
  "";

let cleaned = String(raw).trim();

cleaned = cleaned
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/\s*```$/i, "");

const jsonStart = cleaned.indexOf("{");
if (jsonStart !== -1) {
  cleaned = cleaned.slice(jsonStart);
}

let parsed = null;
let parse_success = false;
let parse_error = null;

try {
  parsed = JSON.parse(cleaned);
  parse_success = true;
} catch (err) {
  parse_error = err.message;
}

return [
  {
    json: {
      success: parse_success,
      parse_error,
      raw_response: raw,
      cleaned_response: cleaned,
      workflow_blueprint: parsed,
      human_readable_plan: parsed?.human_readable_plan || null,
      planner_meta: {
        generated_at: new Date().toISOString()
      }
    }
  }
];

const item = $input.first().json;
const blueprint = item.workflow_blueprint;

const source = $('Edit Fields').first().json;
const plannerContext = $('Build Planner Context').first().json;

const normalize = (val) => {
  try {
    return JSON.parse(val);
  } catch {
    return val;
  }
};

return [
  {
    json: {
      ...item,
      workflow_blueprint: {
        ...blueprint,
        workflow_name: `Project Title: ${source.project_title}`,
        workflow_purpose: `User Goal: ${source.user_goal}`
      },
      runtime: {
        must_use_tools: normalize(source.must_use_tools),
        optional_tools: normalize(source.optional_tools),
        max_steps: Number(String(source.max_steps).replace(/^=/, "")),
        need_human_review:
          source.need_human_review === true ||
          source.need_human_review === "true"
      },
      execution_input: {
        text: plannerContext.input_text || source.input_text || "",
        document_exists: plannerContext.document_exists || false,
        document_text: plannerContext.document_text || ""
      },
      debug_source: source,
      debug_planner_context: plannerContext
    }
  }
];

const item = $input.first().json;

let blueprint = item.workflow_blueprint;
let runtime = item.runtime || {};
let executionInput = item.execution_input || {};

const parseIfString = (value, fieldName) => {
  if (typeof value === "string") {
    try {
      return JSON.parse(value);
    } catch (err) {
      throw new Error(`${fieldName} is a string but could not be parsed as JSON`);
    }
  }
  return value;
};

blueprint = parseIfString(blueprint, "workflow_blueprint");
runtime = parseIfString(runtime, "runtime");
executionInput = parseIfString(executionInput, "execution_input");

if (!blueprint) {
  throw new Error("workflow_blueprint is missing");
}

if (!Array.isArray(blueprint.steps)) {
  throw new Error("workflow_blueprint.steps is missing or is not an array");
}

return [
  {
    json: {
      workflow_name: blueprint.workflow_name,
      workflow_purpose: blueprint.workflow_purpose,
      steps: blueprint.steps,
      runtime,
      execution_input: executionInput,
      debug_blueprint: blueprint,
      debug_execution_input: executionInput,
      execution_state: {
        current_step_index: 0,
        total_steps: blueprint.steps.length,
        logs: [],
        results: {},
        status: "running"
      }
    }
  }
];

const item = $input.first().json;

const steps = item.steps || [];
const runtime = item.runtime || {};
const executionInput = item.execution_input || {};

const logs = [];
const results = {};
let status = "success";

for (const step of steps) {
  const logEntry = {
    step_id: step.step_id,
    step_name: step.name,
    step_type: step.type,
    status: "success",
    detail: ""
  };

  try {
    switch (step.type) {
      case "validation": {
        const rawText = executionInput.text ?? executionInput.inquiry_text ?? "";
        const text = typeof rawText === "string" ? rawText.trim() : "";
        const isValid = text.length > 0;

        results.is_valid = isValid;
        results.validated_text = text;

        logEntry.detail = isValid
          ? `입력값 검증 성공: ${text}`
          : "입력값이 비어 있음";

        if (!isValid) {
          logEntry.status = "failed";
          status = "failed";
        }
        break;
      }

      case "llm_task": {
        if (step.name.includes("분류")) {
          results.category = "refund";
          results.confidence = 0.86;
          logEntry.detail = "더미 LLM 분류 실행 완료: refund";
        } else if (step.name.includes("응답")) {
          results.response_message =
            "안녕하세요. 불편을 드려 죄송합니다. 환불 절차를 도와드리겠습니다.";
          logEntry.detail = "더미 자동 응답 생성 완료";
        } else {
          results.llm_output = "dummy_llm_result";
          logEntry.detail = "더미 LLM 작업 완료";
        }
        break;
      }

      case "reasoning": {
        results.summary =
          "문의 내용을 분석한 결과 환불 관련 요청으로 판단되며 자동 응답 후보를 생성했습니다.";
        logEntry.detail = "더미 reasoning 실행 완료";
        break;
      }

      case "decision": {
        const confidence = results.confidence ?? 0.5;
        const needHumanReview =
          runtime.need_human_review === true || confidence < 0.7;

        results.needs_human_review = needHumanReview;
        results.decision =
          needHumanReview ? "send_to_human_review" : "send_auto_response";

        logEntry.detail = needHumanReview
          ? "사람 검토 필요로 판단"
          : "자동 응답 진행으로 판단";
        break;
      }

      case "integration": {
        if (step.tool === "gmail") {
          if (results.decision === "send_to_human_review") {
            results.sent_status = "dummy_human_review_email_sent";
            logEntry.detail = "담당자 전달 더미 실행 완료";
          } else {
            results.sent_status = "dummy_auto_reply_sent";
            logEntry.detail = "자동 응답 더미 실행 완료";
          }
        } else if (step.tool === "google_sheets") {
          results.sheet_status = "dummy_sheet_row_added";
          logEntry.detail = "Google Sheets 더미 저장 완료";
        } else {
          results.integration_status = `dummy_integration_done:${step.tool || "unknown"}`;
          logEntry.detail = `더미 integration 실행 완료: ${step.tool || "unknown"}`;
        }
        break;
      }

      default: {
        logEntry.status = "skipped";
        logEntry.detail = `지원되지 않는 step type: ${step.type}`;
      }
    }
  } catch (err) {
    logEntry.status = "error";
    logEntry.detail = err.message;
    status = "failed";
  }

  logs.push(logEntry);

  if (status === "failed") {
    break;
  }
}

return [
  {
    json: {
      ...item,
      execution_state: {
        ...item.execution_state,
        logs,
        results,
        status
      }
    }
  }
];

const item = $input.first().json;

const workflowName = item.workflow_name || "";

let scenarioType = "purchase_request";
if (workflowName.includes("회의")) {
  scenarioType = "meeting_followup";
} else if (workflowName.includes("문의")) {
  scenarioType = "customer_inquiry";
}

return [
  {
    json: {
      workflow_name: item.workflow_name,
      workflow_purpose: item.workflow_purpose,
      scenario_type: scenarioType,
      execution_status: item.execution_state.status,
      total_steps: item.execution_state.total_steps,
      executed_steps: item.execution_state.logs.length,
      logs: item.execution_state.logs,
      results: item.execution_state.results,
      document_exists: item.execution_input?.document_exists || false,
      document_preview: (item.execution_input?.document_text || "").slice(0, 300),
      generated_at: new Date().toISOString()
    }
  }
];

const item = $input.first().json;

// 가능한 후보들
let raw =
  item.text ||
  item.content ||
  item.markdown ||
  item.html ||
  item.result?.text ||
  item.result?.content ||
  item.result?.markdown ||
  item.result?.html ||
  "";

// 객체면 문자열화
if (typeof raw !== "string") {
  raw = JSON.stringify(raw);
}

// html/json 형태면 태그나 escape 조금 정리
let cleaned = raw
  .replace(/\\n/g, "\n")
  .replace(/<br\s*\/?>/gi, "\n")
  .replace(/<\/p>/gi, "\n")
  .replace(/<[^>]+>/g, " ")
  .replace(/\s+\n/g, "\n")
  .replace(/\n\s+/g, "\n")
  .replace(/[ \t]+/g, " ")
  .trim();

// 너무 길면 앞부분만
cleaned = cleaned.slice(0, 4000);

return [
  {
    json: {
      document_exists: true,
      document_text: cleaned
    }
  }
];

const original = $('Edit Fields').first().json;
const doc = $input.first().json;

return [
  {
    json: {
      project_title: original.project_title,
      user_goal: original.user_goal,
      input_text: original.input_text,
      max_steps: original.max_steps,
      need_human_review:
        original.need_human_review === true ||
        original.need_human_review === "true",
      document_exists: doc.document_exists || false,
      document_text: doc.document_text || ""
    }
  }
];

const item = $input.first();

const hasDocument = !!item.binary?.pdf_file;

return [
  {
    json: {
      ...item.json,
      has_document: hasDocument
    },
    binary: item.binary
  }
];

const item = $input.first().json;

const scenarioType = item.scenario_type || "";
const results = item.results || {};
const status = item.execution_status || "unknown";
const documentExists = item.document_exists || false;

// 🔹 카테고리 한글 변환
const categoryMap = {
  refund: "환불",
  exchange: "교환",
  shipping: "배송",
  inquiry: "일반 문의",
  unknown: "기타"
};

// 🔹 decision 한글 변환
const decisionMap = {
  send_to_human_review: "담당자 검토 필요",
  send_auto_response: "자동 응답 처리",
  auto_approve: "자동 승인",
  reject: "반려",
  pending: "보류"
};

let naturalMessage = "";
let shortSummary = "";

// ----------------------
// 🟦 회의 후속조치
// ----------------------
if (scenarioType === "meeting_followup") {
  naturalMessage =
    `회의 후속조치 자동화가 ${status === "success" ? "정상적으로 완료되었습니다" : "실행 중 문제가 발생했습니다"}. ` +
    `${documentExists ? "업로드된 회의 문서를 바탕으로 " : ""}` +
    `주요 논의 내용을 정리하고, 후속 작업 항목을 도출하여 결과를 저장했습니다.`;

  shortSummary = "회의 후속조치 항목이 자동으로 정리되어 저장되었습니다.";
}

// ----------------------
// 🟨 고객 문의
// ----------------------
else if (scenarioType === "customer_inquiry") {
  const rawCategory = results.category || "unknown";
  const category = categoryMap[rawCategory] || rawCategory;

  const confidence = results.confidence ?? null;
  const decisionRaw = results.decision || "unknown";
  const decision = decisionMap[decisionRaw] || decisionRaw;

  let decisionText = "";

  if (decisionRaw === "send_to_human_review") {
    decisionText = "추가 확인이 필요하다고 판단되어 담당자에게 전달되었습니다.";
  } else if (decisionRaw === "send_auto_response") {
    decisionText = "자동 응답이 가능한 문의로 판단되어 즉시 처리되었습니다.";
  } else {
    decisionText = `처리 결과는 "${decision}" 상태로 결정되었습니다.`;
  }

  naturalMessage =
    `고객 문의 자동화가 ${status === "success" ? "정상적으로 완료되었습니다" : "실행 중 문제가 발생했습니다"}. ` +
    `${documentExists ? "운영 정책 문서를 참고하여 " : ""}` +
    `문의 내용은 "${category}" 관련 요청으로 분류되었습니다.` +
    `${confidence !== null ? ` (신뢰도 ${confidence})` : ""} ` +
    `${decisionText}`;

  shortSummary =
    `문의 유형: ${category} / 처리 결과: ${decision}`;
}

// ----------------------
// 🟥 구매 요청
// ----------------------
else if (scenarioType === "purchase_request") {
  const decisionRaw = results.decision || "unknown";
  const decision = decisionMap[decisionRaw] || decisionRaw;

  naturalMessage =
    `구매 요청 자동화가 ${status === "success" ? "정상적으로 완료되었습니다" : "실행 중 문제가 발생했습니다"}. ` +
    `${documentExists ? "구매 정책 문서를 기준으로 " : ""}` +
    `요청 내용을 분석한 뒤 승인 여부를 판단했습니다. ` +
    `현재 처리 결과는 "${decision}"입니다.`;

  shortSummary =
    `구매 요청 처리 결과: ${decision}`;
}

// ----------------------
// 🔘 기타 (fallback)
// ----------------------
else {
  naturalMessage =
    `워크플로우가 실행되었으며 현재 상태는 "${status}"입니다.`;

  shortSummary = `상태: ${status}`;
}

return [
  {
    json: {
      ...item,
      natural_message: naturalMessage,
      short_summary: shortSummary
    }
  }
];
